#include <time.h>
#include <omp.h>

#define BLOCK_X 16
#define BLOCK_Y 16
#define PI 3.1415926535897932

const int threads_per_block = 512;

long M = INT_MAX;
int A = 1103515245;
int C = 12345;

typedef int cudaError;
enum {
    cudaSuccess = 0,
    cudaMemcpyHostToDevice = 0,
    cudaMemcpyDeviceToHost = 1
};

static const char *cudaGetErrorString(cudaError e) {
    (void)e;
    return "emulated CUDA error";
}

static cudaError cudaMalloc(void **ptr, size_t size) {
    *ptr = malloc(size);
    return (*ptr != NULL) ? cudaSuccess : 1;
}

static cudaError cudaFree(void *ptr) {
    free(ptr);
    return cudaSuccess;
}

static cudaError cudaMemcpy(void *dst, const void *src, size_t size, int kind) {
    (void)kind;
    memcpy(dst, src, size);
    return cudaSuccess;
}

static cudaError cudaMemset(void *ptr, int value, size_t size) {
    memset(ptr, value, size);
    return cudaSuccess;
}

static cudaError cudaThreadSynchronize(void) {
    return cudaSuccess;
}

long long get_time() {
    struct timeval tv;
    gettimeofday(&tv, NULL);
    return (tv.tv_sec * 1000000LL) + tv.tv_usec;
}

double elapsed_time(long long start_time, long long end_time) {
    return (double)(end_time - start_time) / (1000.0 * 1000.0);
}

void check_error(cudaError e) {
    if (e != cudaSuccess) {
        printf("\nCUDA error: %s\n", cudaGetErrorString(e));
        exit(1);
    }
}

void cuda_print_double_array(double *array_GPU, size_t size) {
