double calcLikelihoodSum(unsigned char *I, int *ind, int numOnes, int index) {
    double likelihoodSum = 0.0;
    int x;
    for (x = 0; numOnes > x; x++) {
        likelihoodSum = likelihoodSum +
                        ((pow((double)(I[ind[index * numOnes + x]] - 100), 2) -
                          pow((double)(I[ind[index * numOnes + x]] - 228), 2)) /
                         50.0);
    }
    return likelihoodSum;
}

void cdfCalc(double *CDF, double *weights, int Nparticles) {
    int x;
    CDF[0] = weights[0];
    for (x = 1; Nparticles > x; x++) {
        CDF[x] = weights[x] + CDF[x - 1];
    }
}

double d_randu(int *seed, int index) {
    long long num = ((long long)A) * seed[index] + C;
    seed[index] = (int)(num % M);
    return fabs(seed[index] / ((double)M));
}

double randu(int *seed, int index) {
    long long num = ((long long)A) * seed[index] + C;
    seed[index] = (int)(num % M);
    return fabs(seed[index] / ((double)M));
}

double randn(int *seed, int index) {
    double u = randu(seed, index);
    double v = randu(seed, index);
    double cosine = cos(2 * PI * v);
    double rt = -2 * log(u);
    return sqrt(rt) * cosine;
}

double test_randn(int *seed, int index) {
    double pi = 3.14159265358979323846;
    double u = randu(seed, index);
    double v = randu(seed, index);
    double cosine = cos(2 * pi * v);
    double rt = -2 * log(u);
    return sqrt(rt) * cosine;
}

double d_randn(int *seed, int index) {
    double pi = 3.14159265358979323846;
    double u = d_randu(seed, index);
    double v = d_randu(seed, index);
    double cosine = cos(2 * pi * v);
    double rt = -2 * log(u);
    return sqrt(rt) * cosine;
}

double updateWeights(double *weights, double *likelihood, int Nparticles) {
    int x;
    double sum = 0;
    for (x = 0; Nparticles > x; x++) {
        weights[x] = weights[x] * exp(likelihood[x]);
        sum = sum + weights[x];
    }
    return sum;
}

int findIndexBin(double *CDF, int beginIndex, int endIndex, double value) {
    if (beginIndex > endIndex)
        return -1;
    int middleIndex;
    while (beginIndex < endIndex) {
        middleIndex = beginIndex + ((endIndex - beginIndex) / 2);
        if (value <= CDF[middleIndex]) {
            if (0 == middleIndex)
                return middleIndex;
            else if (value > CDF[middleIndex - 1])
                return middleIndex;
            else if (value == CDF[middleIndex - 1]) {
                while (value == CDF[middleIndex] && 0 <= middleIndex)
                    middleIndex--;
                middleIndex++;
                return middleIndex;
            }
        }
        if (value < CDF[middleIndex])
            endIndex = middleIndex - 1;
        else
            beginIndex = middleIndex + 1;
    }
    return -1;
}

double dev_round_double(double value) {
    int newValue = (int)(value);
    if (.5f > value - newValue)
        return newValue;
    else
        return newValue++;
}

void find_index_kernel(double *arrayX, double *arrayY, double *CDF, double *u,
                       double *xj, double *yj, double *weights, int Nparticles) {
    (void)weights;
    #pragma omp parallel for
    for (int i = 0; i < Nparticles; i++) {
        int index = -1;
        for (int x = 0; x < Nparticles; x++) {
            if (u[i] <= CDF[x]) {
                index = x;
                break;
            }
        }
        if (-1 == index) {
            index = Nparticles - 1;
        }
        xj[i] = arrayX[index];
        yj[i] = arrayY[index];
    }
}

void normalize_weights_kernel(double *weights, int Nparticles, double *partial_sums,
                              double *CDF, double *u, int *seed) {
    double sumWeights = partial_sums[0];

    #pragma omp parallel for
    for (int i = 0; i < Nparticles; i++) {
        weights[i] = weights[i] / sumWeights;
    }

    cdfCalc(CDF, weights, Nparticles);
    u[0] = (1 / ((double)(Nparticles))) * d_randu(seed, 0);

    {
        double u1 = u[0];
        #pragma omp parallel for
        for (int i = 0; i < Nparticles; i++) {
            u[i] = u1 + i / ((double)(Nparticles));
        }
    }
}

void sum_kernel(double *partial_sums, int Nparticles) {
    (void)Nparticles;
    int num_blocks = (int)ceil((double)Nparticles / (double)threads_per_block);
    double sum = 0.0;
    for (int x = 0; num_blocks > x; x++) {
        sum = sum + partial_sums[x];
    }
    partial_sums[0] = sum;
}

void likelihood_kernel(double *arrayX, double *arrayY, double *xj, double *yj,
                       double *CDF, int *ind, int *objxy, double *likelihood,
                       unsigned char *I, double *u, double *weights,
                       int Nparticles, int countOnes, int max_size, int k,
                       int IszY, int Nfr, int *seed, double *partial_sums) {
    (void)CDF;
    (void)u;

    #pragma omp parallel for
    for (int i = 0; i < Nparticles; i++) {
        arrayX[i] = xj[i];
        arrayY[i] = yj[i];

        weights[i] = 1 / ((double)(Nparticles));

        arrayX[i] = arrayX[i] + 1.0 + 5.0 * d_randn(seed, i);
        arrayY[i] = arrayY[i] - 2.0 + 2.0 * d_randn(seed, i);

        for (int y = 0; countOnes > y; y++) {
            int indX = (int)dev_round_double(arrayX[i]) + objxy[y * 2 + 1];
            int indY = (int)dev_round_double(arrayY[i]) + objxy[y * 2];
            ind[i * countOnes + y] = abs(indX * IszY * Nfr + indY * Nfr + k);
            if (max_size <= ind[i * countOnes + y])
                ind[i * countOnes + y] = 0;
        }
        likelihood[i] = calcLikelihoodSum(I, ind, countOnes, i);
        likelihood[i] = likelihood[i] / countOnes;
        weights[i] = weights[i] * exp(likelihood[i]);
    }

    int num_blocks = (int)ceil((double)Nparticles / (double)threads_per_block);

    #pragma omp parallel for
    for (int block = 0; block < num_blocks; block++) {
        int start = block * threads_per_block;
        int end = start + threads_per_block;
        if (end > Nparticles)
            end = Nparticles;
        double sum = 0.0;
        for (int i = start; i < end; i++) {
            sum += weights[i];
        }
        partial_sums[block] = sum;
    }
}

double roundDouble(double value) {
    int newValue = (int)(value);
    if (.5 > value - newValue)
        return newValue;
    else
        return newValue++;
}

void setIf(int testValue, int newValue, unsigned char *array3D,
           int *dimX, int *dimY, int *dimZ) {
    int x, y, z;
    #pragma omp parallel for collapse(3) private(x, y, z)
    for (x = 0; *dimX > x; x++) {
        for (y = 0; *dimY > y; y++) {
            for (z = 0; *dimZ > z; z++) {
                if (testValue == array3D[x * *dimY * *dimZ + y * *dimZ + z])
                    array3D[x * *dimY * *dimZ + y * *dimZ + z] = (unsigned char)newValue;
            }
        }
    }
}

void addNoise(unsigned char *array3D, int *dimX, int *dimY, int *dimZ, int *seed) {
    int x, y, z;
    for (x = 0; *dimX > x; x++) {
        for (y = 0; *dimY > y; y++) {
            for (z = 0; *dimZ > z; z++) {
                array3D[x * *dimY * *dimZ + y * *dimZ + z] =
                    array3D[x * *dimY * *dimZ + y * *dimZ + z] +
                    (unsigned char)(5 * randn(seed, 0));
            }
        }
    }
}

void strelDisk(int *disk, int radius) {
    int diameter = radius * 2 - 1;
    int x, y;
    #pragma omp parallel for collapse(2) private(x, y)
    for (x = 0; diameter > x; x++) {
        for (y = 0; diameter > y; y++) {
            double distance = sqrt(pow((double)(x - radius + 1), 2) +
                                   pow((double)(y - radius + 1), 2));
            if (radius > distance)
                disk[x * diameter + y] = 1;
            else
                disk[x * diameter + y] = 0;
        }
    }
}

void dilate_matrix(unsigned char *matrix, int posX, int posY, int posZ,
                   int dimX, int dimY, int dimZ, int error) {
    int startX = posX - error;
    while (0 > startX)
        startX++;
    int startY = posY - error;
    while (0 > startY)
        startY++;
    int endX = posX + error;
    while (dimX < endX)
        endX--;
    int endY = posY + error;
    while (dimY < endY)
        endY--;
    int x, y;
    for (x = startX; endX > x; x++) {
        for (y = startY; endY > y; y++) {
            double distance = sqrt(pow((double)(x - posX), 2) +
                                   pow((double)(y - posY), 2));
            if (error > distance)
                matrix[x * dimY * dimZ + y * dimZ + posZ] = 1;
        }
    }
}

void imdilate_disk(unsigned char *matrix, int dimX, int dimY, int dimZ,
                   int error, unsigned char *newMatrix) {
    int x, y, z;
    for (z = 0; dimZ > z; z++) {
        for (x = 0; dimX > x; x++) {
            for (y = 0; dimY > y; y++) {
                if (1 == matrix[x * dimY * dimZ + y * dimZ + z]) {
                    dilate_matrix(newMatrix, x, y, z, dimX, dimY, dimZ, error);
                }
            }
        }
    }
}

void getneighbors(int *se, int numOnes, int *neighbors, int radius) {
    int x, y;
    int neighY = 0;
    int center = radius - 1;
    int diameter = radius * 2 - 1;
    for (x = 0; diameter > x; x++) {
        for (y = 0; diameter > y; y++) {
            if (se[x * diameter + y]) {
                neighbors[neighY * 2] = (int)(y - center);
                neighbors[neighY * 2 + 1] = (int)(x - center);
                neighY++;
            }
        }
    }
}

void videoSequence(unsigned char *I, int IszX, int IszY, int Nfr, int *seed) {
    int k;
    int max_size = IszX * IszY * Nfr;

    int x0 = (int)roundDouble(IszY / 2.0);
    int y0 = (int)roundDouble(IszX / 2.0);
    I[x0 * IszY * Nfr + y0 * Nfr + 0] = 1;

    int xk, yk, pos;
    for (k = 1; Nfr > k; k++) {
        xk = abs(x0 + (k - 1));
        yk = abs(y0 - 2 * (k - 1));
        pos = yk * IszY * Nfr + xk * Nfr + k;
        if (max_size <= pos)
            pos = 0;
        I[pos] = 1;
    }

    unsigned char *newMatrix = (unsigned char *)calloc((size_t)IszX * IszY * Nfr, sizeof(unsigned char));
    if (newMatrix == NULL) {
        exit(1);
    }
    imdilate_disk(I, IszX, IszY, Nfr, 5, newMatrix);
    int x, y;
    #pragma omp parallel for collapse(3) private(x, y, k)
    for (x = 0; IszX > x; x++) {
        for (y = 0; IszY > y; y++) {
            for (k = 0; Nfr > k; k++) {
                I[x * IszY * Nfr + y * Nfr + k] =
                    newMatrix[x * IszY * Nfr + y * Nfr + k];
            }
        }
    }
    free(newMatrix);

    setIf(0, 100, I, &IszX, &IszY, &Nfr);
    setIf(1, 228, I, &IszX, &IszY, &Nfr);

    addNoise(I, &IszX, &IszY, &Nfr, seed);
}

int findIndex(double *CDF, int lengthCDF, double value) {
    int index = -1;
    int x;
    for (x = 0; lengthCDF > x; x++) {
        if (value <= CDF[x]) {
            index = x;
            break;
        }
    }
    if (-1 == index) {
        return lengthCDF - 1;
    }
    return index;
}

void particleFilter(unsigned char *I, int IszX, int IszY, int Nfr, int *seed, int Nparticles) {
    int max_size = IszX * IszY * Nfr;

    double xe = roundDouble(IszY / 2.0);
    double ye = roundDouble(IszX / 2.0);

    int radius = 5;
    int diameter = radius * 2 - 1;
    int *disk = (int *)malloc(diameter * diameter * sizeof(int));
    if (disk == NULL) {
        exit(1);
    }
    strelDisk(disk, radius);
    int countOnes = 0;
    int x, y;
    for (x = 0; diameter > x; x++) {
        for (y = 0; diameter > y; y++) {
            if (1 == disk[x * diameter + y])
                countOnes++;
        }
    }
    int *objxy = (int *)malloc(countOnes * 2 * sizeof(int));
    if (objxy == NULL) {
        exit(1);
    }
    getneighbors(disk, countOnes, objxy, radius);

    double *weights = (double *)malloc(sizeof(double) * Nparticles);
    if (weights == NULL) {
        exit(1);
    }
    #pragma omp parallel for
    for (x = 0; Nparticles > x; x++) {
        weights[x] = 1 / ((double)(Nparticles));
    }

    double *likelihood = (double *)malloc(sizeof(double) * Nparticles);
    double *arrayX = (double *)malloc(sizeof(double) * Nparticles);
    double *arrayY = (double *)malloc(sizeof(double) * Nparticles);
    double *xj = (double *)malloc(sizeof(double) * Nparticles);
    double *yj = (double *)malloc(sizeof(double) * Nparticles);
    double *CDF = (double *)malloc(sizeof(double) * Nparticles);

    double *arrayX_GPU;
    double *arrayY_GPU;
    double *xj_GPU;
    double *yj_GPU;
    double *CDF_GPU;
    double *likelihood_GPU;
    unsigned char *I_GPU;
    double *weights_GPU;
    int *objxy_GPU;

    int *ind = (int *)malloc(sizeof(int) * countOnes * Nparticles);
    int *ind_GPU;
    double *u = (double *)malloc(sizeof(double) * Nparticles);
    double *u_GPU;
    int *seed_GPU;
    double *partial_sums;

    if (likelihood == NULL || arrayX == NULL || arrayY == NULL || xj == NULL ||
        yj == NULL || CDF == NULL || ind == NULL || u == NULL) {
        exit(1);
    }

    check_error(cudaMalloc((void **)&arrayX_GPU, sizeof(double) * Nparticles));
    check_error(cudaMalloc((void **)&arrayY_GPU, sizeof(double) * Nparticles));
    check_error(cudaMalloc((void **)&xj_GPU, sizeof(double) * Nparticles));
    check_error(cudaMalloc((void **)&yj_GPU, sizeof(double) * Nparticles));
    check_error(cudaMalloc((void **)&CDF_GPU, sizeof(double) * Nparticles));
    check_error(cudaMalloc((void **)&u_GPU, sizeof(double) * Nparticles));
    check_error(cudaMalloc((void **)&likelihood_GPU, sizeof(double) * Nparticles));

    check_error(cudaMemset((void *)likelihood_GPU, 0, sizeof(double) * Nparticles));
    check_error(cudaMalloc((void **)&weights_GPU, sizeof(double) * Nparticles));
    check_error(cudaMalloc((void **)&I_GPU, sizeof(unsigned char) * IszX * IszY * Nfr));
    check_error(cudaMalloc((void **)&objxy_GPU, sizeof(int) * 2 * countOnes));
    check_error(cudaMalloc((void **)&ind_GPU, sizeof(int) * countOnes * Nparticles));
    check_error(cudaMalloc((void **)&seed_GPU, sizeof(int) * Nparticles));
    check_error(cudaMalloc((void **)&partial_sums, sizeof(double) * Nparticles));

    #pragma omp parallel for
    for (x = 0; Nparticles > x; x++) {
        xj[x] = xe;
        yj[x] = ye;
    }

    long long send_start = get_time();
    check_error(cudaMemcpy(I_GPU, I, sizeof(unsigned char) * IszX * IszY * Nfr, cudaMemcpyHostToDevice));
    check_error(cudaMemcpy(objxy_GPU, objxy, sizeof(int) * 2 * countOnes, cudaMemcpyHostToDevice));
    check_error(cudaMemcpy(weights_GPU, weights, sizeof(double) * Nparticles, cudaMemcpyHostToDevice));
    check_error(cudaMemcpy(xj_GPU, xj, sizeof(double) * Nparticles, cudaMemcpyHostToDevice));
    check_error(cudaMemcpy(yj_GPU, yj, sizeof(double) * Nparticles, cudaMemcpyHostToDevice));
    check_error(cudaMemcpy(seed_GPU, seed, sizeof(int) * Nparticles, cudaMemcpyHostToDevice));
    long long send_end = get_time();
    printf("TIME TO SEND TO GPU: %f\n", elapsed_time(send_start, send_end));
    int num_blocks = (int)ceil((double)Nparticles / (double)threads_per_block);

    for (int k = 1; Nfr > k; k++) {
        likelihood_kernel(arrayX_GPU, arrayY_GPU, xj_GPU, yj_GPU, CDF_GPU, ind_GPU,
                          objxy_GPU, likelihood_GPU, I_GPU, u_GPU, weights_GPU,
                          Nparticles, countOnes, max_size, k, IszY, Nfr, seed_GPU,
                          partial_sums);

        sum_kernel(partial_sums, Nparticles);

        normalize_weights_kernel(weights_GPU, Nparticles, partial_sums, CDF_GPU, u_GPU, seed_GPU);

        find_index_kernel(arrayX_GPU, arrayY_GPU, CDF_GPU, u_GPU, xj_GPU, yj_GPU, weights_GPU, Nparticles);
    }

    (void)num_blocks;
    cudaThreadSynchronize();
    long long back_time = get_time();

    cudaFree(xj_GPU);
    cudaFree(yj_GPU);
    cudaFree(CDF_GPU);
    cudaFree(u_GPU);
    cudaFree(likelihood_GPU);
    cudaFree(I_GPU);
    cudaFree(objxy_GPU);
    cudaFree(ind_GPU);
    cudaFree(seed_GPU);
    cudaFree(partial_sums);

    long long free_time = get_time();
    check_error(cudaMemcpy(arrayX, arrayX_GPU, sizeof(double) * Nparticles, cudaMemcpyDeviceToHost));
    long long arrayX_time = get_time();
    check_error(cudaMemcpy(arrayY, arrayY_GPU, sizeof(double) * Nparticles, cudaMemcpyDeviceToHost));
    long long arrayY_time = get_time();
    check_error(cudaMemcpy(weights, weights_GPU, sizeof(double) * Nparticles, cudaMemcpyDeviceToHost));
    long long back_end_time = get_time();
    printf("GPU Execution: %lf\n", elapsed_time(send_end, back_time));
    printf("FREE TIME: %lf\n", elapsed_time(back_time, free_time));
    printf("TIME TO SEND BACK: %lf\n", elapsed_time(back_time, back_end_time));
    printf("SEND ARRAY X BACK: %lf\n", elapsed_time(free_time, arrayX_time));
    printf("SEND ARRAY Y BACK: %lf\n", elapsed_time(arrayX_time, arrayY_time));
    printf("SEND WEIGHTS BACK: %lf\n", elapsed_time(arrayY_time, back_end_time));

    xe = 0;
    ye = 0;

    for (x = 0; Nparticles > x; x++) {
        xe = xe + (arrayX[x] * weights[x]);
        ye = ye + (arrayY[x] * weights[x]);
    }
    printf("XE: %lf\n", xe);
    printf("YE: %lf\n", ye);
    double distance = sqrt(pow((double)(xe - (int)roundDouble(IszY / 2.0)), 2) +
                           pow((double)(ye - (int)roundDouble(IszX / 2.0)), 2));
    printf("%lf\n", distance);

    cudaFree(weights_GPU);
    cudaFree(arrayY_GPU);
    cudaFree(arrayX_GPU);

    free(disk);
    free(objxy);
    free(weights);
    free(likelihood);
    free(arrayX);
    free(arrayY);
    free(xj);
    free(yj);
    free(CDF);
    free(ind);
    free(u);
}

int main(int argc, char *argv[]) {
    char *usage = "double.out -x <dimX> -y <dimY> -z <Nfr> -np <Nparticles>";

    if (9 != argc) {
        printf("%s\n", usage);
        return 0;
    }

    if (strcmp(argv[1], "-x") || strcmp(argv[3], "-y") || strcmp(argv[5], "-z") || strcmp(argv[7], "-np")) {
        printf("%s\n", usage);
        return 0;
    }

    int IszX, IszY, Nfr, Nparticles;

    if (sscanf(argv[2], "%d", &IszX) == EOF) {
        printf("ERROR: dimX input is incorrect");
        return 0;
    }

    if (0 >= IszX) {
        printf("dimX must be > 0\n");
        return 0;
    }

    if (sscanf(argv[4], "%d", &IszY) == EOF) {
        printf("ERROR: dimY input is incorrect");
        return 0;
    }

    if (0 >= IszY) {
        printf("dimY must be > 0\n");
        return 0;
    }

    if (sscanf(argv[6], "%d", &Nfr) == EOF) {
        printf("ERROR: Number of frames input is incorrect");
        return 0;
    }

    if (0 >= Nfr) {
        printf("number of frames must be > 0\n");
        return 0;
    }

    if (sscanf(argv[8], "%d", &Nparticles) == EOF) {
        printf("ERROR: Number of particles input is incorrect");
        return 0;
    }

    if (0 >= Nparticles) {
        printf("Number of particles must be > 0\n");
        return 0;
    }

    int *seed = (int *)malloc(sizeof(int) * Nparticles);
    if (seed == NULL) {
        return 1;
    }
    int i;
    for (i = 0; Nparticles > i; i++)
        seed[i] = (int)time(0) * i;

    unsigned char *I = (unsigned char *)calloc((size_t)IszX * IszY * Nfr, sizeof(unsigned char));
    if (I == NULL) {
        free(seed);
        return 1;
    }
    long long start = get_time();

    videoSequence(I, IszX, IszY, Nfr, seed);
    long long endVideoSequence = get_time();
    printf("VIDEO SEQUENCE TOOK %f\n", elapsed_time(start, endVideoSequence));

    particleFilter(I, IszX, IszY, Nfr, seed, Nparticles);
    long long endParticleFilter = get_time();
    printf("PARTICLE FILTER TOOK %f\n", elapsed_time(endVideoSequence, endParticleFilter));
    printf("ENTIRE PROGRAM TOOK %f\n", elapsed_time(start, endParticleFilter));

    free(seed);
    free(I);
    return 0;
}
